namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            CreateNotification("Welcome to the notifications demo!"),
            CreateNotification("Your profile was updated."),
            CreateNotification("New comment on your post."),
        ]);
    }

    /// <summary>Returns all notifications that currently exist.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns notifications added after the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateIncoming()
    {
        string[] messages =
        [
            "You have a new follower!",
            "Your build succeeded.",
            "Deployment to production complete.",
            "Someone mentioned you in a comment.",
            "New pull-request review requested.",
            "Disk usage alert: 85% full.",
            "Scheduled backup finished.",
        ];

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message) =>
        new(_nextId++, message, DateTime.UtcNow);
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<BlazorNotifications.Services.Notification>? PersistedNotifications { get; set; }

    protected override void OnInitialized()
    {
        // Restore from persisted prerender state, or load fresh.
        PersistedNotifications ??= NotificationService.GetAll();
        notifications = PersistedNotifications;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only start polling once the component is interactive (never during prerender).
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate a new notification arriving on the server side.
            NotificationService.SimulateIncoming();

            var latest = notifications.Count > 0
                ? notifications.Max(n => n.Timestamp)
                : DateTime.MinValue;

            var newItems = NotificationService.GetSince(latest);

            if (newItems.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    notifications.AddRange(newItems);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

