namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            CreateNotification("Welcome to the notifications demo!"),
            CreateNotification("Your profile was updated."),
            CreateNotification("New comment on your post."),
        ]);
    }

    /// <summary>Returns all notifications that currently exist.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns notifications added after the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateIncoming()
    {
        string[] messages =
        [
            "You have a new follower!",
            "Your build succeeded.",
            "Deployment to production complete.",
            "Someone mentioned you in a comment.",
            "New pull-request review requested.",
            "Disk usage alert: 85% full.",
            "Scheduled backup finished.",
        ];

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message) =>
        new(_nextId++, message, DateTime.UtcNow);
}

